+.card {
+  border: 1px solid var(--border);
+  background: var(--panel);
+  border-radius: 18px;
+  padding: 16px;
+  box-shadow: 0 18px 40px rgba(0, 0, 0, 0.25);
+  animation: rise 0.35s ease;
+}
+
+.card-title {
+  font-family: var(--font-display);
+  font-size: 18px;
+}
+
+.card-sub {
+  color: var(--muted);
