+}
+
+.mono {
+  font-family: var(--mono);
+}
+
+.callout {
+  padding: 10px 12px;
+  border-radius: 12px;
+  background: rgba(255, 255, 255, 0.05);
+  border: 1px solid rgba(255, 255, 255, 0.08);
+}
+
+.callout.danger {
+  border-color: rgba(255, 92, 92, 0.4);
