+  padding: 12px;
+  background: rgba(0, 0, 0, 0.2);
+}
+
+.list-main {
+  display: grid;
+  gap: 6px;
+}
+
+.list-title {
+  font-weight: 600;
+}
+
+.list-sub {
+  color: var(--muted);
+  font-size: 13px;
+}
+
+.list-meta {
+  text-align: right;
