+import { html, nothing } from "lit";
+
+import { clampText } from "../format";
+import type { SkillStatusEntry, SkillStatusReport } from "../types";
+
+export type SkillsProps = {
+  loading: boolean;
+  report: SkillStatusReport | null;
+  error: string | null;
+  filter: string;
+  edits: Record<string, string>;
+  busyKey: string | null;
+  onFilterChange: (next: string) => void;
+  onRefresh: () => void;
+  onToggle: (skillKey: string, enabled: boolean) => void;
+  onEdit: (skillKey: string, value: string) => void;
+  onSaveKey: (skillKey: string) => void;
+  onInstall: (name: string, installId: string) => void;
+};
+
+export function renderSkills(props: SkillsProps) {
+  const skills = props.report?.skills ?? [];
+  const filter = props.filter.trim().toLowerCase();
+  const filtered = filter
+    ? skills.filter((skill) =>
+        [skill.name, skill.description, skill.source]
+          .join(" ")
+          .toLowerCase()
+          .includes(filter),
+      )
+    : skills;
+
+  return html`
+    <section class="card">
+      <div class="row" style="justify-content: space-between;">
+        <div>
+          <div class="card-title">Skills</div>
+          <div class="card-sub">Bundled, managed, and workspace skills.</div>
+        </div>
+        <button class="btn" ?disabled=${props.loading} @click=${props.onRefresh}>
+          ${props.loading ? "Loading…" : "Refresh"}
+        </button>
+      </div>
+
+      <div class="filters" style="margin-top: 14px;">
+        <label class="field" style="flex: 1;">
+          <span>Filter</span>
+          <input
+            .value=${props.filter}
+            @input=${(e: Event) =>
+              props.onFilterChange((e.target as HTMLInputElement).value)}
+            placeholder="Search skills"
+          />
+        </label>
+        <div class="muted">${filtered.length} shown</div>
+      </div>
+
+      ${props.error
+        ? html`<div class="callout danger" style="margin-top: 12px;">${props.error}</div>`
+        : nothing}
+
+      ${filtered.length === 0
+        ? html`<div class="muted" style="margin-top: 16px;">No skills found.</div>`
+        : html`
+            <div class="list" style="margin-top: 16px;">
+              ${filtered.map((skill) => renderSkill(skill, props))}
+            </div>
+          `}
+    </section>
+  `;
+}
+
+function renderSkill(skill: SkillStatusEntry, props: SkillsProps) {
+  const busy = props.busyKey === skill.skillKey || props.busyKey === skill.name;
+  const apiKey = props.edits[skill.skillKey] ?? "";
+  return html`
+    <div class="list-item">
+      <div class="list-main">
+        <div class="list-title">
+          ${skill.emoji ? `${skill.emoji} ` : ""}${skill.name}
+        </div>
+        <div class="list-sub">${clampText(skill.description, 140)}</div>
+        <div class="chip-row" style="margin-top: 6px;">
+          <span class="chip">${skill.source}</span>
+          <span class="chip ${skill.eligible ? "chip-ok" : "chip-warn"}">
+            ${skill.eligible ? "eligible" : "blocked"}
+          </span>
+          ${skill.disabled ? html`<span class="chip chip-warn">disabled</span>` : nothing}
+        </div>
+        ${skill.missing.bins.length + skill.missing.env.length + skill.missing.config.length > 0
+          ? html`
+              <div class="muted" style="margin-top: 6px;">
+                Missing: ${[
+                  ...skill.missing.bins.map((b) => `bin:${b}`),
+                  ...skill.missing.env.map((e) => `env:${e}`),
+                  ...skill.missing.config.map((c) => `config:${c}`),
+                ].join(", ")}
+              </div>
+            `
+          : nothing}
+      </div>
+      <div class="list-meta">
+        <div class="row" style="justify-content: flex-end; flex-wrap: wrap;">
+          <button
+            class="btn"
+            ?disabled=${busy}
+            @click=${() => props.onToggle(skill.skillKey, skill.disabled)}
+          >
+            ${skill.disabled ? "Enable" : "Disable"}
+          </button>
+          ${skill.install.length > 0
+            ? html`<button
+                class="btn"
+                ?disabled=${busy}
+                @click=${() => props.onInstall(skill.name, skill.install[0].id)}
+              >
+                ${skill.install[0].label}
+              </button>`
+            : nothing}
+        </div>
+        ${skill.primaryEnv
+          ? html`
+              <div class="field" style="margin-top: 10px;">
+                <span>API key</span>
+                <input
+                  type="password"
+                  .value=${apiKey}
+                  @input=${(e: Event) =>
+                    props.onEdit(skill.skillKey, (e.target as HTMLInputElement).value)}
+                />
+              </div>
+              <button
+                class="btn primary"
+                style="margin-top: 8px;"
+                ?disabled=${busy}
+                @click=${() => props.onSaveKey(skill.skillKey)}
+              >
+                Save key
+              </button>
+            `
+          : nothing}
+      </div>
+    </div>
+  `;
+}
